grader.test:
try:
    nth_fibonacci(-1)
    raise AssertionError('should raise ValueError')
except ValueError:
    pass
assert nth_fibonacci(40)==102334155

assert flatten_dict({'a':{'b':1,'c':{'d':2}},'e':3})=={'a.b':1,'a.c.d':2,'e':3}
assert flatten_dict({})=={}
assert flatten_dict({'a':1})=={'a':1}

assert flatten_dict({'x':{'y':{'z':5}}})=={'x.y.z':5}
assert flatten_dict({'a':{'b':1}},sep='/')=={'a/b':1}
d={'a':{'b':1}}
flatten_dict(d)
assert d=={'a':{'b':1}}

try:
    clamp(5,10,0)
    raise AssertionError('should raise ValueError')
except ValueError:
    pass

assert word_frequencies('the cat the dog the')=={'the':3,'cat':1,'dog':1}
assert word_frequencies('')=={}
assert list(word_frequencies('b a b a c').items())==[('a',2),('b',2),('c',1)]

assert parse_query_string('a=1&b=2&a=3')=={'a':['1','3'],'b':['2']}
assert parse_query_string('')=={}
assert parse_query_string('x=')=={'x':['']}

assert parse_query_string('k')=={'k':['']}
assert parse_query_string('a=1&a=1')=={'a':['1','1']}
assert parse_query_string('a=b=c')=={'a':['b=c']}

assert safe_get({'a':{'b':None}},'a.b','D') is None
assert safe_get({'a':1},'a.b','D')=='D'
d={'a':{'b':2}}
safe_get(d,'a.b')
assert d=={'a':{'b':2}}

try:
    validate_email(123)
    raise AssertionError('non-str should raise TypeError')
except TypeError:
    pass
try:
    validate_email(None)
    raise AssertionError('None should raise TypeError')
except TypeError:
    pass
assert validate_email('a@bcom') is False
